
import React, { useEffect, useState, useRef, useImperativeHandle,forwardRef  } from 'react'
import * as _Util from '../../store/Util'
import '../../styles/_styles.css'
import { Icon_Cmpt } from '.'

const Icon2 = Icon_Cmpt()


const SearchProdComponent = forwardRef((props,ref) => {

  const {
    placeholderCode,
    type,
    icon
  } = props;
  


  const [initialize, setInitialize] = useState(false);
  const [obs,setObs] = useState(0);
  const cmpRef = useRef("")

  useEffect(() => {
    if(!initialize){
      setInitialize(true);
    }
  })

  let isOpen = false;
  let _type = type || "text";
  let txt = cmpRef && cmpRef.current.value

  const handleInput = () => {
    setObs(cmpRef.current.value)
    if(typeof props.updChanges === "function"){
      props.updChanges(cmpRef.current.value);
    }
  }

  const clearTx = () => {
    cmpRef.current.value = "";
    if(typeof props.updChanges === "function"){
      props.updChanges("");
    }
  }

  const handleBur = () => {
    if(cmpRef.current.value.length > 0 &&  typeof props.updBlurChanges === "function"){
      props.updBlurChanges(cmpRef.current.value);
    }
  }

  const handleKey = (e) => {
    if(e.keyCode===13){
      if(cmpRef.current.value.length > 0 &&  typeof props.updBlurChanges === "function"){
        props.updBlurChanges(cmpRef.current.value);
      }
    }
  }

  useImperativeHandle(ref, () => ({
    updValue(v) {
      cmpRef.current.value = v;
      setObs(cmpRef.current.value)
    }
  }));


  return (

    <div className={`z86TMb ${isOpen?"FNFY6c":""}`}>
      <button 
      className="FrV7Ge" 
      type="button" 
      aria-label="Buscar con Google">
        <div className="kzJn9c">
          <span className="Vx3Zn">
            <Icon2 name={icon} />
          </span>
        </div>
      </button>
      <input className="r7gAOb yyJm8b" ref={cmpRef} 
        maxlength="2048" 
        // id="SREsRA" 
        name="q" 
        type={_type}
        aria-autocomplete="both" 
        aria-haspopup="false" 
        auto-capitalize="off" 
        auto-complete="off" 
        auto-correct="off" 
        spell-check="false" 
        placeholder={_Util.translatetext(placeholderCode)}
        onChange={handleInput}
        onBlur={handleBur}
        onKeyDown={handleKey}
      />
      <button  className="hxXCL" type="button"  style={{visibility:txt && txt.length>0?"":"hidden"}} >
        <span aria-label="Borrar búsqueda" onClick={clearTx} >×</span>
      </button>
    </div>
  )

})



export default SearchProdComponent;